mapper.sql:
		FROM (
			SELECT	AB.*
					, ROW_NUMBER() OVER (


				 		ORDER BY	BT_TYPE_NAME ${sortDirect}


				 		ORDER BY	SC_CODENM ${sortDirect}


				 		ORDER BY	MN_NAME ${sortDirect}


				 		ORDER BY	BT_HTML_YN ${sortDirect}


				 		ORDER BY	BT_THUMBNAIL_YN ${sortDirect}


				 		ORDER BY	BT_REPLY_YN ${sortDirect}


				 		ORDER BY	BT_COMMENT_YN ${sortDirect}


				 		ORDER BY	BT_SECRET_YN ${sortDirect}


				 		ORDER BY	BT_UPLOAD_YN ${sortDirect}


				 		ORDER BY	BT_HTMLMAKER_PLUS_YN ${sortDirect}


				 		ORDER BY	BT_EMAIL ${sortDirect}


				 		ORDER BY	BT_PREVIEW_YN ${sortDirect}


				 		ORDER BY ROWNUM


			 		) RNUM
			FROM (
				SELECT 	BT_KEYNO
	    				, BT_TYPE_NAME
			    		, CASE WHEN BT_HTML_YN = 'Y' THEN 'O' ELSE 'X' END BT_HTML_YN
			    		, CASE WHEN BT_THUMBNAIL_YN = 'Y' THEN 'O' ELSE 'X' END BT_THUMBNAIL_YN
			    		, CASE WHEN BT_REPLY_YN = 'Y' THEN 'O' ELSE 'X' END BT_REPLY_YN
			    		, CASE WHEN BT_COMMENT_YN = 'Y' THEN 'O' ELSE 'X' END BT_COMMENT_YN
			    		, CASE WHEN BT_SECRET_YN = 'Y' THEN 'O' ELSE 'X' END BT_SECRET_YN
			    		, CASE WHEN BT_UPLOAD_YN = 'Y' THEN 'O' ELSE 'X' END BT_UPLOAD_YN
			    		, CASE WHEN BT_HTMLMAKER_PLUS_YN = 'Y' THEN 'O' ELSE 'X' END BT_HTMLMAKER_PLUS_YN
			    		, CASE WHEN BT_EMAIL_YN = 'Y' THEN BT_EMAIL_ADDRESS ELSE 'X' END BT_EMAIL
 		    			, CASE WHEN BT_PREVIEW_YN = 'Y' THEN 'O' ELSE 'X' END BT_PREVIEW_YN
			    		, BT_TICKET_PR_YN
			    		, BT_SNS_YN
			    		, BT_RSS_YN
			    		, SC_CODENM 
                        , ( SELECT    LISTAGG(MN_NAME || '(' || (SELECT MN_NAME FROM s_menu_manager WHERE MN_KEYNO = MN.MN_HOMEDIV_C AND MN_DEL_YN = 'N') || ')',',')  WITHIN GROUP (ORDER BY BT_KEYNO)
                            FROM s_menu_manager MN
			    			LEFT JOIN s_home_manager HM
							ON MN.MN_HOMEDIV_C = HM.HM_MN_HOMEDIV_C
                            WHERE 	MN_BT_KEYNO = B.BT_KEYNO 
			    			AND 	MN_DEL_YN = 'N'
			    			AND 	HM.HM_USE_YN = 'Y'
			    			AND		MN.MN_PAGEDIV_C = 'SC_TFOVO'
			    		) MN_NAME
			    		, CASE 
                        WHEN B.BT_LIST_KEYNO = 'list' then '기본 리스트 폼'  
                        WHEN B.BT_LIST_KEYNO = 'no_detail' then '상세페이지 없는 리스트 폼'  
                        WHEN B.BT_LIST_KEYNO = 'gallery' then '갤러리 폼'  
                        WHEN B.BT_LIST_KEYNO = 'calendar' then '캘린더 폼' 
                        ELSE  (SELECT BST_TITLE FROM b_board_skin_template WHERE BST_KEYNO = B.BT_LIST_KEYNO ) 
                        END BT_LIST_TITLE  
	   			FROM b_board_type B 
			    LEFT JOIN (
				    		SELECT * 
				    		FROM s_common_code_sub
				    		WHERE SC_MC_IN_C = 'AC'
				    		ORDER BY SC_CODELV
			    		) C
			 	ON B.BT_CODEKEY = C.SC_KEYNO
				WHERE BT_USE_YN = 'Y'
			) AB
		WHERE 1=1




 		AND		BT_TYPE_NAME 			LIKE '%' || #{item.searchKeyword} || '%'					


 		AND		SC_CODENM				LIKE '%' || #{item.searchKeyword} || '%'					


 		AND		MN_NAME 				LIKE '%' || #{item.searchKeyword} || '%'					


 		AND		BT_HTML_YN			=	#{item.searchKeyword}					


 		AND		BT_THUMBNAIL_YN 	=	#{item.searchKeyword}						


 		AND		BT_REPLY_YN 		=	#{item.searchKeyword}						


 		AND		BT_COMMENT_YN 		=	#{item.searchKeyword}						


 		AND		BT_SECRET_YN 		=	#{item.searchKeyword}					


 		AND		BT_UPLOAD_YN 		=	#{item.searchKeyword}					


 		AND		BT_HTMLMAKER_PLUS_YN 			=	#{item.searchKeyword}					


 		AND		BT_EMAIL 				LIKE '%' || #{item.searchKeyword} || '%'						


 		AND		BT_PREVIEW_YN 		=	#{item.searchKeyword}					


 		AND (
 				BT_TYPE_NAME 			LIKE '%' || #{item.searchKeyword} || '%' 	OR
 				SC_CODENM				LIKE '%' || #{item.searchKeyword} || '%' 	OR
 				MN_NAME 				LIKE '%' || #{item.searchKeyword} || '%' 	OR
 				BT_HTML_YN			=	#{item.searchKeyword}  					OR
 				BT_THUMBNAIL_YN 	=	#{item.searchKeyword}  					OR
 				BT_REPLY_YN 		=	#{item.searchKeyword}  					OR
 				BT_COMMENT_YN 		=	#{item.searchKeyword}  					OR
				BT_SECRET_YN 		=	#{item.searchKeyword} 					OR
 				BT_UPLOAD_YN 		=	#{item.searchKeyword} 					OR
 				BT_HTMLMAKER_PLUS_YN 			=	#{item.searchKeyword} 					OR
 				BT_EMAIL 				LIKE '%' || #{item.searchKeyword} || '%' 		OR
 				BT_PREVIEW_YN 		=	#{item.searchKeyword}
 		)							




		)AA

mapper.select:
    	SELECT	* 


		WHERE 1=1
		AND 	RNUM BETWEEN  #{firstIndex}+1 AND #{lastIndex}

SELECT * FROM b_board_type
WHERE BT_USE_YN	=	'Y'
AND   BT_KEYNO  =	#{BT_KEYNO}

mapper.update:

UPDATE b_board_type 
SET		BT_USE_YN			= 'N'
WHERE   BT_KEYNO			= #{BT_KEYNO}
